#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#ifdef RD_WG_SIZE_0_0
        #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define BLOCK_SIZE RD_WG_SIZE
#else
        #define BLOCK_SIZE 16
#endif

void lud_diagonal_omp(float *m, int matrix_dim, int offset)
{
  int i, j;
  float shadow[BLOCK_SIZE][BLOCK_SIZE];

  int array_offset = offset * matrix_dim + offset;
  for (i = 0; i < BLOCK_SIZE; i++) {
    for (int t = 0; t < BLOCK_SIZE; t++) {
      shadow[i][t] = m[array_offset + t];
    }
    array_offset += matrix_dim;
  }

  for (i = 0; i < BLOCK_SIZE - 1; i++) {
    for (int t = i + 1; t < BLOCK_SIZE; t++) {
      for (j = 0; j < i; j++)
        shadow[t][i] -= shadow[t][j] * shadow[j][i];
      shadow[t][i] /= shadow[i][i];
    }

    for (int t = 0; t < BLOCK_SIZE; t++) {
      for (j = 0; j < i + 1; j++)
        shadow[i + 1][t] -= shadow[i + 1][j] * shadow[j][t];
    }
  }

  array_offset = (offset + 1) * matrix_dim + offset;
  for (i = 1; i < BLOCK_SIZE; i++) {
    for (int t = 0; t < BLOCK_SIZE; t++) {
      m[array_offset + t] = shadow[i][t];
    }
    array_offset += matrix_dim;
  }
}

void lud_perimeter_omp(float *m, int matrix_dim, int offset, int block_idx)
{
  float dia[BLOCK_SIZE][BLOCK_SIZE];
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];

  int i, j, array_offset;
  int idx;

  for (idx = 0; idx < BLOCK_SIZE; idx++) {
    array_offset = offset * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE / 2; i++) {
      dia[i][idx] = m[array_offset + idx];
      array_offset += matrix_dim;
    }

    array_offset = offset * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
      peri_row[i][idx] = m[array_offset + (block_idx + 1) * BLOCK_SIZE + idx];
      array_offset += matrix_dim;
    }
  }

  for (idx = 0; idx < BLOCK_SIZE; idx++) {
    array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
    for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
      dia[i][idx] = m[array_offset + idx];
      array_offset += matrix_dim;
    }

    array_offset = (offset + (block_idx + 1) * BLOCK_SIZE) * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
      peri_col[i][idx] = m[array_offset + idx];
      array_offset += matrix_dim;
    }
  }

  for (idx = 0; idx < BLOCK_SIZE; idx++) {
    for (i = 1; i < BLOCK_SIZE; i++) {
      for (j = 0; j < i; j++)
        peri_row[i][idx] -= dia[i][j] * peri_row[j][idx];
    }
  }

  for (idx = 0; idx < BLOCK_SIZE; idx++) {
    for (i = 0; i < BLOCK_SIZE; i++) {
      for (j = 0; j < i; j++)
        peri_col[idx][i] -= peri_col[idx][j] * dia[j][i];
      peri_col[idx][i] /= dia[i][i];
    }
  }

  for (idx = 0; idx < BLOCK_SIZE; idx++) {
    array_offset = (offset + 1) * matrix_dim + offset;
    for (i = 1; i < BLOCK_SIZE; i++) {
      m[array_offset + (block_idx + 1) * BLOCK_SIZE + idx] = peri_row[i][idx];
      array_offset += matrix_dim;
    }
  }

  for (idx = 0; idx < BLOCK_SIZE; idx++) {
    array_offset = (offset + (block_idx + 1) * BLOCK_SIZE) * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
      m[array_offset + idx] = peri_col[i][idx];
      array_offset += matrix_dim;
    }
  }
}

void lud_internal_omp(float *m, int matrix_dim, int offset, int block_grid_x, int block_grid_y)
{
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];
  int i;
  float sum;

  int global_row_id = offset + (block_grid_y + 1) * BLOCK_SIZE;
  int global_col_id = offset + (block_grid_x + 1) * BLOCK_SIZE;

  for (int ty = 0; ty < BLOCK_SIZE; ty++) {
    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
      peri_row[ty][tx] = m[(offset + ty) * matrix_dim + global_col_id + tx];
      peri_col[ty][tx] = m[(global_row_id + ty) * matrix_dim + offset + tx];
    }
  }

  for (int ty = 0; ty < BLOCK_SIZE; ty++) {
    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
      sum = 0;
      for (i = 0; i < BLOCK_SIZE; i++)
        sum += peri_col[ty][i] * peri_row[i][tx];
      m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
    }
  }
}

void lud_omp(float *m, int matrix_dim)
{
  int i = 0;
  int num_blocks = (matrix_dim - BLOCK_SIZE) / BLOCK_SIZE;

  for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
    lud_diagonal_omp(m, matrix_dim, i);

    int perimeter_blocks = (matrix_dim - i) / BLOCK_SIZE - 1;
    for (int block_idx = 0; block_idx < perimeter_blocks; block_idx++) {
      lud_perimeter_omp(m, matrix_dim, i, block_idx);
    }

    int internal_blocks = (matrix_dim - i) / BLOCK_SIZE - 1;
    for (int block_y = 0; block_y < internal_blocks; block_y++) {
      for (int block_x = 0; block_x < internal_blocks; block_x++) {
        lud_internal_omp(m, matrix_dim, i, block_x, block_y);
      }
    }
  }
  lud_diagonal_omp(m, matrix_dim, i);
}
